class ParameterTuner:
    PRESETS = {
        'extraction': {'temperature': 0.0, 'max_tokens': 500,  'frequency_penalty': 0.0, 'top_p': 1.0},
        'code':       {'temperature': 0.2, 'max_tokens': 2000, 'frequency_penalty': 0.1, 'top_p': 1.0},
        'creative':   {'temperature': 1.0, 'max_tokens': 2000, 'frequency_penalty': 0.5, 'top_p': 0.95},
        'chat':       {'temperature': 0.7, 'max_tokens': 1000, 'frequency_penalty': 0.3, 'top_p': 1.0},
    }
    KEYWORDS = {
        'extraction': ['json', 'extract', 'parse', 'structured', 'field'],
        'code':       ['write', 'function', 'class', 'implement', 'code', 'algorithm'],
        'creative':   ['story', 'poem', 'creative', 'imagine', 'fiction'],
    }

    def classify(self, task_description: str) -> str:
        lower = task_description.lower()
        for task_type, keywords in self.KEYWORDS.items():
            if any(kw in lower for kw in keywords):
                return task_type
        return 'chat'

    def get_parameters(self, task_description: str) -> dict:
        task_type = self.classify(task_description)
        return {'task_type': task_type, **self.PRESETS[task_type]}


# Test
tuner = ParameterTuner()
for prompt in [
    'Extract the name and email from this text as JSON',
    'Write a Python function to sort a linked list',
    'Tell me about the weather today'
]:
    params = tuner.get_parameters(prompt)
    print(f"'{prompt[:40]}...' → {params['task_type']}, temp={params['temperature']}")
